<header class="app-page-head"><div><p class="eyebrow">Filtern, nicht vergessen</p><h1><?=e($title)?></h1><p><?=count($entries)?> persönliche Einträge.</p></div><a class="button" href="<?=u('/app/scan')?>">Neuer Scan</a></header><form method="get" action="<?=u('/app/library')?>" class="filter-bar"><label class="search-field"><span class="sr-only">Bibliothek durchsuchen</span><input type="search" name="q" value="<?=e($filters['q']??'')?>" placeholder="Produkt, Marke oder Barcode"></label><select name="sort" aria-label="Sortierung"><option value="recent" <?=($filters['sort']??'')==='recent'?'selected':''?>>Zuletzt bewertet</option><option value="rating" <?=($filters['sort']??'')==='rating'?'selected':''?>>Beste Wertung</option><option value="name" <?=($filters['sort']??'')==='name'?'selected':''?>>Name A–Z</option></select><select name="min_rating" aria-label="Mindestwertung"><option value="">Alle Wertungen</option><?php for($i=10;$i>=5;$i--):?><option value="<?=$i?>" <?=((string)($filters['min_rating']??'')===(string)$i)?'selected':''?>>ab <?=$i?>/10</option><?php endfor;?></select><button class="button button-small" type="submit">Filtern</button></form><nav class="quick-filters"><a href="<?=u('/app/favorites')?>">Favoriten</a><a href="<?=u('/app/buy-again')?>">Wieder kaufen</a><a href="<?=u('/app/never-again')?>">Nie wieder</a><a href="<?=u('/app/library?movie_night=1')?>">Filmabend</a></nav><?php if(!$entries):?><div class="empty-state"><h2>Hier ist noch nichts.</h2><p>Ändere die Filter oder scanne einen neuen Snack.</p><a class="button" href="<?=u('/app/scan')?>">Snack scannen</a></div><?php else:?><div class="product-grid"><?php foreach($entries as $entry)include __DIR__.'/../partials/product-card.php';?></div><?php endif;?>
